#!/usr/bin/env bash
#SBATCH --job-name=pressure-splitcp4-vtp
#SBATCH --partition=alvis
#SBATCH --account=naiss2025-22-1747
#SBATCH --gres=gpu:A100:1
#SBATCH --ntasks=1
#SBATCH --cpus-per-task=16
#SBATCH --time=08:00:00
#SBATCH --output=logs/pressure_splitcp4_vtp_%j.out
#SBATCH --error=logs/pressure_splitcp4_vtp_%j.err
#
# Write VTP files for the averaged 4-fold ordinary split-CP pressure outputs.
# Requires:
#   results/pressure_splitcp_4fold/averaged_test_npz/
#   results/pressure_splitcp_4fold/averaged_qhat.json
# which are generated by scripts/run_splitcp_4fold.sh with MAKE_AVG_NPZ=1.
#
set -euo pipefail

if [[ -z "${PROJECT_ROOT:-}" ]]; then
  if [[ -n "${SLURM_SUBMIT_DIR:-}" ]]; then
    _submit="$(cd "${SLURM_SUBMIT_DIR}" && pwd)"
    if [[ "$(basename "${_submit}")" == "scripts" ]]; then
      PROJECT_ROOT="$(cd "${_submit}/.." && pwd)"
    else
      PROJECT_ROOT="${_submit}"
    fi
  else
    _SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]:-$0}")" && pwd)"
    PROJECT_ROOT="$(cd "${_SCRIPT_DIR}/.." && pwd)"
  fi
fi
export PROJECT_ROOT
cd "${PROJECT_ROOT}"
mkdir -p "${PROJECT_ROOT}/logs"

if command -v conda >/dev/null 2>&1; then
    eval "$(conda shell.bash hook)"
elif [[ -f "/cephyr/users/chaoxi/Alvis/Desktop/mimer_naiss2025-23-604/Liyujing/Anaconda3/etc/profile.d/conda.sh" ]]; then
    source "/cephyr/users/chaoxi/Alvis/Desktop/mimer_naiss2025-23-604/Liyujing/Anaconda3/etc/profile.d/conda.sh"
else
    echo "[ERROR] conda not found. Initialize conda or source conda.sh."
    exit 1
fi
conda activate geotran_pressure
export LD_LIBRARY_PATH="${CONDA_PREFIX}/lib:${LD_LIBRARY_PATH:-}"

ROOT="${SPLITCP4_ROOT:-${PROJECT_ROOT}/results/pressure_splitcp_4fold}"
TEST_DIR="${SPLITCP4_TEST_DIR:-${ROOT}/averaged_test_npz}"
QHAT_JSON="${SPLITCP4_QHAT_JSON:-${ROOT}/averaged_qhat.json}"
OUT_DIR="${SPLITCP4_VTP_OUT:-${ROOT}/vtp_averaged}"
STRIDE="${VTP_STRIDE:-1}"
MAX_CASES="${VTP_MAX_CASES:-}"
PRESSURE_ONLY="${PRESSURE_ONLY:-0}"
NO_BOUNDS="${NO_BOUNDS:-0}"

if [[ ! -d "${TEST_DIR}" ]]; then
  echo "[ERROR] Missing averaged test npz directory: ${TEST_DIR}" >&2
  echo "Run: MAKE_AVG_NPZ=1 sbatch scripts/run_splitcp_4fold.sh" >&2
  exit 1
fi
if [[ ! -f "${QHAT_JSON}" ]]; then
  echo "[ERROR] Missing averaged qhat json: ${QHAT_JSON}" >&2
  exit 1
fi

ARGS=(
  --test-dir "${TEST_DIR}"
  --qhat-json "${QHAT_JSON}"
  --out "${OUT_DIR}"
  --modes global_abs point_sigma case_sigma
  --stride "${STRIDE}"
)
if [[ -n "${MAX_CASES}" ]]; then
  ARGS+=(--max-cases "${MAX_CASES}")
fi
if [[ "${PRESSURE_ONLY}" == "1" ]]; then
  ARGS+=(--pressure-only)
fi
if [[ "${NO_BOUNDS}" == "1" ]]; then
  ARGS+=(--no-bounds)
fi

python "${PROJECT_ROOT}/cp_write_vtp_global_point_case.py" "${ARGS[@]}"
echo "[OK] VTP files written under ${OUT_DIR}"
